squads_json = json.dumps(squads_data)

# Find and replace the SQUADS object
start_marker = 'window.SQUADS = {'
idx = content.find(start_marker)

if idx == -1:
    print("ERROR: Cannot find SQUADS start marker")
    exit(1)

# Find the matching closing brace
brace_count = 0
in_string = False
i = idx + len(start_marker) - 1

while i < len(content):
    if content[i] == '"' and (i == 0 or content[i-1] != '\\'):
        in_string = not in_string
    elif not in_string:
        if content[i] == '{':
            brace_count += 1
        elif content[i] == '}':
            brace_count -= 1
            if brace_count == 0:
                end_idx = i + 1
                break
    i += 1

new_content = content[:idx] + f'window.SQUADS = {squads_json};' + content[end_idx:]

with open('SportsRookie Overlay (Offline).html', 'w', encoding='utf-8') as f:
    f.write(new_content)

print("SUCCESS: Updated SQUADS with 48 teams!")
print(f"Teams integrated: {len(squads_data)}")
